import{_ as a,c as s,o as r,d as i}from"./plugin-vue_export-helper.f7ed9f25.js";const k='{"title":"\u041D\u0438\u0440\u0430\u043B\u0430\u043C\u0431\u0430 \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430","description":"","frontmatter":{"title":"\u041D\u0438\u0440\u0430\u043B\u0430\u043C\u0431\u0430 \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430","subtitle":"\u041D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043E \u0431\u0435\u0437\u043E\u043F\u043E\u0440\u043D\u043E\u043C","sans":"\u0928\u093F\u0930\u093E\u0932\u092E\u094D\u092C\u094B\u092A\u0928\u093F\u0937\u0924\u094D","trans":"nir\u0101lambopani\u1E63at","tags":"text","date":"2021-01-01T00:00:00.000Z"},"relativePath":"texts/niralamba/index.md","lastUpdated":1625417248563}',n={},t=i('<p>\u041C\u0430\u043B\u0430\u044F \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430 \u043A\u0430\u043D\u043E\u043D\u0430 \u041C\u0443\u043A\u0442\u0438\u043A\u0430 (\u043E\u043D\u0430 \u0438\u0434\u0451\u0442 34-\u043E\u0439 \u0432 \u0441\u043F\u0438\u0441\u043A\u0435 \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434); \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u043A \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430\u043C \u0428\u0443\u043A\u043B\u0430-\u042F\u0434\u0436\u0443\u0440-\u0432\u0435\u0434\u044B \u0438 \u0421\u0430\u043C\u0430\u043D\u044C\u044F-\u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430\u043C</p><p class="sans">\u0965 \u0928\u093F\u0930\u093E\u0932\u092E\u094D\u092C\u094B\u092A\u0928\u093F\u0937\u0924\u094D \u0965</p><p class="trans">.. nir\u0101lambopani\u1E63at \u0965</p><div class="stanza"><p class="sans">\u092F\u0924\u094D\u0930\u093E\u0932\u092E\u094D\u092C\u093E\u0932\u092E\u094D\u092C\u093F\u092D\u093E\u0935\u094B \u0935\u093F\u0926\u094D\u092F\u0924\u0947 \u0928 \u0915\u0926\u093E\u091A\u0928 \u0964<br> \u091C\u094D\u091E\u0935\u093F\u091C\u094D\u091E\u0938\u092E\u094D\u092F\u0917\u094D\u091C\u094D\u091E\u093E\u0932\u092E\u094D\u092C\u0902 \u0928\u093F\u0930\u093E\u0932\u092E\u094D\u092C\u0902 \u0939\u0930\u093F\u0902 \u092D\u091C\u0947 \u0965</p><p class="trans">yatr\u0101lamb\u0101lambibh\u0101vo vidyate na kad\u0101cana \u0964<br> j\xF1avij\xF1asamyagj\xF1\u0101lamba\u1E41 nir\u0101lamba\u1E41 hari\u1E41 bhaje \u0965</p></div><div class="stanza"><p class="sans">\u0950 \u092A\u0942\u0930\u094D\u0923\u092E\u0926\u0903 \u092A\u0942\u0930\u094D\u0923\u092E\u093F\u0926\u0902 \u092A\u0942\u0930\u094D\u0923\u093E\u0924\u094D\u092A\u0942\u0930\u094D\u0923\u092E\u0941\u0926\u091A\u094D\u092F\u0924\u0947 \u0964<br> \u092A\u0942\u0930\u094D\u0923\u0938\u094D\u092F \u092A\u0942\u0930\u094D\u0923\u092E\u093E\u0926\u093E\u092F \u092A\u0942\u0930\u094D\u0923\u092E\u0947\u0935\u093E\u0935\u0936\u093F\u0937\u094D\u092F\u0924\u0947 \u0965<br> \u0950 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0965</p><p class="trans">o\u1E41 p\u016Br\u1E47amada\u1E25 p\u016Br\u1E47amida\u1E41 p\u016Br\u1E47\u0101tp\u016Br\u1E47amudacyate \u0964<br> p\u016Br\u1E47asya p\u016Br\u1E47am\u0101d\u0101ya p\u016Br\u1E47amev\u0101va\u015Bi\u1E63yate \u0965<br> o\u1E41 \u015B\u0101nti\u1E25 \u015B\u0101nti\u1E25 \u015B\u0101nti\u1E25 \u0965</p><p>\u041E\u043C. \u0422\u043E \u2014 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C, \u0438 \u044D\u0442\u043E \u2014 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C. \u0411\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C \u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0438\u0437 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u0438, \u041E\u0431\u0440\u0435\u0442\u0430\u044F \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0433\u043E, \u043E\u043D\u0430 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u043B\u0438\u0448\u044C \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C\u044E. \u041E\u043C! \u041F\u043E\u043A\u043E\u0439! \u041F\u043E\u043A\u043E\u0439! \u041F\u043E\u043A\u043E\u0439!</p></div><div class="stanza"><p class="sans">\u0950 \u0928\u092E\u0903 \u0936\u093F\u0935\u093E\u092F \u0917\u0941\u0930\u0935\u0947 \u0938\u091A\u094D\u091A\u093F\u0926\u093E\u0928\u0928\u094D\u0926 \u092E\u0942\u0930\u094D\u0924\u092F\u0947 \u0964<br> \u0928\u093F\u0937\u094D\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u093E\u092F \u0936\u093E\u0928\u094D\u0924\u093E\u092F \u0928\u093F\u0930\u093E\u0932\u092E\u094D\u092C\u093E\u092F \u0924\u0947\u091C\u0938\u0947 \u0965</p><p class="trans">o\u1E41 nama\u1E25 \u015Biv\u0101ya gurave saccid\u0101nanda m\u016Brtaye \u0964<br> ni\u1E63prapa\xF1c\u0101ya \u015B\u0101nt\u0101ya nir\u0101lamb\u0101ya tejase \u0965</p><p>\xAB\u041E\u043C. \u041F\u043E\u043A\u043B\u043E\u043D \u0411\u043B\u0430\u0433\u043E\u043C\u0443 (\u0428\u0438\u0432\u0435), [\u0432\u044B\u0441\u0448\u0435\u043C\u0443] \u0413\u0443\u0440\u0443, \u043E\u0431\u0440\u0430\u0437\u0443 \u0411\u044B\u0442\u0438\u044F, \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430! \u041F\u043E\u043A\u043B\u043E\u043D \u0422\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u043D\u043E\u043C\u0443 [\u0413\u043E\u0441\u043F\u043E\u0434\u0443], [\u041A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0441\u0442\u044C \u0431\u043B\u0430\u0436\u0435\u043D\u043D\u044B\u0439] \u041F\u043E\u043A\u043E\u0439, \u041D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u043C\u0443 (\u041D\u0438\u0440\u0430\u043B\u0430\u043C\u0431\u0435), \u0421\u0438\u044F\u044E\u0449\u0435\u043C\u0443!\xBB</p></div><div class="stanza"><p class="sans">\u0928\u093F\u0930\u093E\u0932\u092E\u094D\u092C\u0902 \u0938\u092E\u093E\u0936\u094D\u0930\u093F\u0924\u094D\u092F \u0938\u093E\u0932\u092E\u094D\u092C\u0902 \u0935\u093F\u091C\u0939\u093E\u0924\u093F \u092F\u0903 \u0964<br> \u0938 \u0938\u0902\u0928\u094D\u092F\u093E\u0938\u0940 \u091A \u092F\u094B\u0917\u0940 \u091A \u0915\u0948\u0935\u0932\u094D\u092F\u0902 \u092A\u0926\u092E\u0936\u094D\u0928\u0941\u0924\u0947 \u0964<br> \u090F\u0937\u092E\u091C\u094D\u091E\u093E\u0928\u091C\u0928\u094D\u0924\u0942\u0928\u093E\u0902 \u0938\u092E\u0938\u094D\u0924\u093E\u0930\u093F\u0937\u094D\u091F\u0936\u093E\u0928\u094D\u0924\u092F\u0947 \u0964<br> \u092F\u0926\u094D\u092F\u0926\u094D\u092C\u094B\u0926\u094D\u0927\u0935\u094D\u092F\u092E\u0916\u093F\u0932\u0902 \u0924\u0926\u093E\u0936\u0919\u094D\u0915\u094D\u092F \u092C\u094D\u0930\u0935\u0940\u092E\u094D\u092F\u0939\u092E\u094D \u0965</p><p class="trans">nir\u0101lamba\u1E41 sam\u0101\u015Britya s\u0101lamba\u1E41 vijah\u0101ti ya\u1E25 \u0964<br> sa sa\u1E41ny\u0101s\u012B ca yog\u012B ca kaivalya\u1E41 padama\u015Bnute \u0964<br> e\u1E63amaj\xF1\u0101najant\u016Bn\u0101\u1E41 samast\u0101ri\u1E63\u1E6Da\u015B\u0101ntaye \u0964<br> yadyadboddhavyamakhila\u1E41 tad\u0101\u015Ba\u1E45kya brav\u012Bmyaham \u0965</p><p>[\u0411\u0440\u0430\u0445\u043C\u0430 \u0441\u043A\u0430\u0437\u0430\u043B:] \xAB\u0422\u043E\u0442, \u043A\u0442\u043E [\u0432\u0441\u0435\u0446\u0435\u043B\u043E] \u043F\u0440\u0435\u0434\u0430\u043B\u0441\u044F \u0441\u0432\u043E\u0431\u043E\u0434\u0435, \u043F\u043E\u0431\u0435\u0434\u0438\u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438, [\u0435\u0441\u0442\u044C \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u0439] \u0441\u0430\u043D\u043D\u044C\u044F\u0441\u0438\u043D \u0438 \u0439\u043E\u0433\u0438\u043D, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F (\u043A\u0430\u0439\u0432\u0430\u043B\u044C\u0438). \u042F \u0431\u0435\u0437 \u043A\u043E\u043B\u0435\u0431\u0430\u043D\u0438\u0439 \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u0442\u043E, \u0447\u0442\u043E [\u043D\u0443\u0436\u043D\u043E \u0434\u043B\u044F] \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F \u043C\u0438\u0440\u0430 \u0438 \u0434\u043B\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F \u0441\u0443\u0449\u0435\u0441\u0442\u0432, [\u0436\u0438\u0432\u0443\u0449\u0438\u0445 \u0432] \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0438, \u043E\u0442 \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0439\xBB.</p></div><div class="stanza"><p class="sans">\u0915\u093F\u0902 \u092C\u094D\u0930\u0939\u094D\u092E \u0964<br> \u0915 \u0908\u0936\u094D\u0935\u0930\u0903 \u0964<br> \u0915\u094B \u091C\u0940\u0935\u0903 \u0964<br> \u0915\u093E \u092A\u094D\u0930\u0915\u0943\u0924\u093F\u0903 \u0964<br> \u0915\u0903 \u092A\u0930\u092E\u093E\u0924\u094D\u092E\u093E \u0964<br> \u0915\u094B \u092C\u094D\u0930\u0939\u094D\u092E\u093E \u0964<br> \u0915\u094B \u0935\u093F\u0937\u094D\u0923\u0941\u0903 \u0964<br> \u0915\u094B \u0930\u0941\u0926\u094D\u0930\u0903 \u0964<br> \u0915 \u0907\u0928\u094D\u0926\u094D\u0930\u0903 \u0964<br> \u0915\u0903 \u0936\u092E\u0928\u0903 \u0964<br> \u0915\u0903 \u0938\u0942\u0930\u094D\u092F\u0903 \u0964<br> \u0915\u0936\u094D\u091A\u0928\u094D\u0926\u094D\u0930\u0903 \u0964<br> \u0915\u0947 \u0938\u0941\u0930\u093E\u0903 \u0964<br> \u0915\u0947 \u0905\u0938\u0941\u0930\u093E\u0903 \u0964<br> \u0915\u0947 \u092A\u093F\u0936\u093E\u091A\u093E\u0903 \u0964<br> \u0915\u0947 \u092E\u0928\u0941\u0937\u094D\u092F\u093E\u0903 \u0964<br> \u0915\u093E\u0903 \u0938\u094D\u0924\u094D\u0930\u093F\u092F\u0903 \u0964<br> \u0915\u0947 \u092A\u0936\u094D\u0935\u093E\u0926\u092F\u0903 \u0964<br> \u0915\u093F\u0902 \u0938\u094D\u0925\u093E\u0935\u0930\u092E\u094D \u0964<br> \u0915\u0947 \u092C\u094D\u0930\u093E\u0939\u094D\u092E\u0923\u093E\u0926\u092F\u0903 \u0964<br> \u0915\u093E \u091C\u093E\u0924\u093F\u0903 \u0964<br> \u0915\u093F\u0902 \u0915\u0930\u094D\u092E \u0964<br> \u0915\u093F\u092E\u0915\u0930\u094D\u092E \u0964<br> \u0915\u093F\u0902 \u091C\u094D\u091E\u093E\u0928\u092E\u094D \u0964<br> \u0915\u093F\u092E\u091C\u094D\u091E\u093E\u0928\u092E\u094D \u0964<br> \u0915\u093F\u0902 \u0938\u0941\u0916\u092E\u094D \u0964<br> \u0915\u093F\u0902 \u0926\u0941\u0903\u0916\u092E\u094D \u0964<br> \u0915\u0903 \u0938\u094D\u0935\u0930\u094D\u0917\u0903 \u0964<br> \u0915\u094B \u0928\u0930\u0915\u0903 \u0964<br> \u0915\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u0915\u094B \u092E\u094B\u0915\u094D\u0936\u0903 \u0964<br> \u0915 \u0909\u092A\u093E\u0938\u094D\u092F\u0903 \u0964<br> \u0915\u0903 \u0936\u093F\u0937\u094D\u092F\u0903 \u0964<br> \u0915\u094B \u0935\u093F\u0926\u094D\u0935\u093E\u0928\u094D \u0964<br> \u0915\u094B \u092E\u0942\u0922\u0903 \u0964<br> \u0915\u093F\u092E\u093E\u0938\u0941\u0930\u092E\u094D \u0964<br> \u0915\u093F\u0902 \u0924\u092A\u0903 \u0964<br> \u0915\u093F\u0902 \u092A\u0930\u092E\u0902 \u092A\u0926\u092E\u094D \u0964<br> \u0915\u093F\u0902 \u0917\u094D\u0930\u093E\u0939\u094D\u092F\u092E\u094D \u0964<br> \u0915\u093F\u092E\u0917\u094D\u0930\u093E\u0939\u094D\u092F\u092E\u094D \u0964</p><p class="trans">ki\u1E41 brahma \u0964<br> ka \u012B\u015Bvara\u1E25 \u0964<br> ko j\u012Bva\u1E25 \u0964<br> k\u0101 prak\u1E5Bti\u1E25 \u0964<br> ka\u1E25 param\u0101tm\u0101 \u0964<br> ko brahm\u0101 \u0964<br> ko vi\u1E63\u1E47u\u1E25 \u0964<br> ko rudra\u1E25 \u0964<br> ka indra\u1E25 \u0964<br> ka\u1E25 \u015Bamana\u1E25 \u0964<br> ka\u1E25 s\u016Brya\u1E25 \u0964<br> ka\u015Bcandra\u1E25 \u0964<br> ke sur\u0101\u1E25 \u0964<br> ke asur\u0101\u1E25 \u0964<br> ke pi\u015B\u0101c\u0101\u1E25 \u0964<br> ke manu\u1E63y\u0101\u1E25 \u0964<br> k\u0101\u1E25 striya\u1E25 \u0964<br> ke pa\u015Bv\u0101daya\u1E25 \u0964<br> ki\u1E41 sth\u0101varam \u0964<br> ke br\u0101hma\u1E47\u0101daya\u1E25 \u0964<br> k\u0101 j\u0101ti\u1E25 \u0964<br> ki\u1E41 karma \u0964<br> kimakarma \u0964<br> ki\u1E41 j\xF1\u0101nam \u0964<br> kimaj\xF1\u0101nam \u0964<br> ki\u1E41 sukham \u0964<br> ki\u1E41 du\u1E25kham \u0964<br> ka\u1E25 svarga\u1E25 \u0964<br> ko naraka\u1E25 \u0964<br> ko bandha\u1E25 \u0964<br> ko mok\u015Ba\u1E25 \u0964<br> ka up\u0101sya\u1E25 \u0964<br> ka\u1E25 \u015Bi\u1E63ya\u1E25 \u0964<br> ko vidv\u0101n \u0964<br> ko m\u016B\u1E0Dha\u1E25 \u0964<br> kim\u0101suram \u0964<br> ki\u1E41 tapa\u1E25 \u0964<br> ki\u1E41 parama\u1E41 padam \u0964<br> ki\u1E41 gr\u0101hyam \u0964<br> kimagr\u0101hyam \u0964<br> ka\u1E25 sa\u1E41ny\u0101s\u012Bty\u0101ha\u015Ba\u1E45ky\u0101ha brahmeti \u0964<br></p><p>[\u0411\u0440\u0430\u0445\u043C\u0443 \u0441\u043F\u0440\u043E\u0441\u0438\u043B\u0438:] \xAB\u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0411\u0440\u0430\u0445\u043C\u0430\u043D? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0413\u043E\u0441\u043F\u043E\u0434\u044C (\u0418\u0448\u0432\u0430\u0440\u0430)? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0436\u0438\u0432\u0430\u044F \u0434\u0443\u0448\u0430 (\u0434\u0436\u0438\u0432\u0430)? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u043F\u0440\u0430\u043A\u0440\u0438\u0442\u044B? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0412\u044B\u0441\u0448\u0430\u044F \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C (\u041F\u0430\u0440\u0430\u043C\u0430\u0442\u043C\u0430\u043D)? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0411\u0440\u0430\u0445\u043C\u0430? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0412\u0438\u0448\u043D\u0443? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0420\u0443\u0434\u0440\u0430? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0418\u043D\u0434\u0440\u0430? \u041A\u0442\u043E \u0435\u0441\u0442\u044C [\u0431\u043E\u0433] \u0441\u043C\u0435\u0440\u0442\u0438 (\u042F\u043C\u0430)? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0421\u0443\u0440\u044C\u044F? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0427\u0430\u043D\u0434\u0440\u0430? \u041A\u0442\u043E \u0442\u0430\u043A\u0438\u0435 \u0431\u043E\u0433\u0438? \u041A\u0442\u043E \u0442\u0430\u043A\u0438\u0435 \u0434\u0435\u043C\u043E\u043D\u044B \u0430\u0441\u0443\u0440\u044B? \u041A\u0442\u043E \u0442\u0430\u043A\u0438\u0435 \u043F\u0438\u0448\u0430\u0447\u0438? \u041A\u0442\u043E \u0442\u0430\u043A\u0438\u0435 \u043C\u0443\u0436\u0447\u0438\u043D\u044B? \u041A\u0442\u043E \u0442\u0430\u043A\u0438\u0435 \u0436\u0435\u043D\u0449\u0438\u043D\u044B? \u041A\u0442\u043E \u0442\u0430\u043A\u0438\u0435 \u0436\u0438\u0432\u043E\u0442\u043D\u044B\u0435 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 [\u0436\u0438\u0432\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430]? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u043D\u0435\u0434\u0432\u0438\u0436\u0438\u043C\u043E\u0435 (\u0441\u0442\u0445\u0430\u0432\u0430\u0440\u0430)? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0431\u0440\u0430\u0445\u043C\u0430\u043D\u044B \u0438 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 [\u0442\u0440\u0438 \u043A\u0430\u0441\u0442\u044B]? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u043A\u0430\u0441\u0442\u0430 (\u0434\u0436\u0430\u0442\u0438)? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 (\u043A\u0430\u0440\u043C\u0430)? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F (\u0430\u043A\u0430\u0440\u043C\u0430)? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u0437\u043D\u0430\u043D\u0438\u0435 (\u0434\u0436\u043D\u044F\u043D\u0430)? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u043D\u0435\u0437\u043D\u0430\u043D\u0438\u0435? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u0441\u0447\u0430\u0441\u0442\u044C\u0435? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u043D\u0435\u0441\u0447\u0430\u0441\u0442\u044C\u0435? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u0440\u0430\u0439 (\u0441\u0432\u0430\u0440\u0433\u0430)? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u0430\u0434 (\u043D\u0430\u0440\u0430\u043A\u0430)? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 (\u043C\u043E\u043A\u0448\u0430)? \u041A\u043E\u0433\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0443\u0447\u0435\u043D\u0438\u043A? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u043F\u043E\u0437\u043D\u0430\u0432\u0448\u0438\u0439? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0433\u043B\u0443\u043F\u0435\u0446? \u0427\u0442\u043E \u0434\u0435\u043C\u043E\u043D\u0438\u0447\u043D\u043E? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u043F\u043E\u0434\u0432\u0438\u0436\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u043E (;\u0442\u0430\u043F\u0430\u0441)? \u0427\u0442\u043E \u0435\u0441\u0442\u044C \u0432\u044B\u0441\u0448\u0435\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435? \u0427\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0442\u044C? \u0427\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u0432\u0435\u0440\u0433\u0430\u0442\u044C? \u041A\u0442\u043E \u0435\u0441\u0442\u044C \u0441\u0430\u043D\u043D\u044C\u044F\u0441\u0438\u043D?\xBB</p></div><div class="stanza"><a href="#s1" id="s1" class="num">1</a><p class="sans">\u0915\u0903 \u0938\u0902\u0928\u094D\u092F\u093E\u0938\u0940\u0924\u094D\u092F\u093E\u0939\u0936\u0919\u094D\u0915\u094D\u092F\u093E\u0939 \u092C\u094D\u0930\u0939\u094D\u092E\u0947\u0924\u093F \u0964<br> \u0938 \u0939\u094B\u0935\u093E\u091A \u092E\u0939\u0926\u0939\u0919\u094D\u0915\u093E\u0930\u092A\u0943\u0925\u093F\u0935\u094D\u092F\u092A\u094D\u0924\u0947\u091C\u094B\u0935\u093E\u092F\u094D\u0935\u093E\u0915\u093E\u0936\u0924\u094D\u0935\u0947\u0928 \u092C\u0943\u0939\u0926\u094D\u0930\u0942\u092A\u0947\u0923\u093E\u0923\u094D\u0921\u0915\u094B\u0936\u0947\u0928 \u0915\u0930\u094D\u092E\u091C\u094D\u091E\u093E\u0928\u093E\u0930\u094D\u0925\u0930\u0942\u092A\u0924\u092F\u093E \u092D\u093E\u0938\u092E\u093E\u0928\u092E\u0926\u094D\u0935\u093F\u0924\u0940\u092F\u092E\u0916\u093F\u0932\u094B\u092A\u093E\u0927\u093F\u0935\u093F\u0928\u093F\u0930\u094D\u092E\u0941\u0915\u094D\u0924\u0902 \u0924\u0924\u094D\u0938\u0915\u0932\u0936\u0915\u094D\u0924\u094D\u092F\u0941\u092A\u092C\u0943\u0902\u0939\u093F\u0924\u092E\u0928\u093E\u0926\u094D\u092F\u0928\u0928\u094D\u0924\u0902 \u0936\u0941\u0926\u094D\u0927\u0902 \u0936\u093F\u0935\u0902 \u0936\u093E\u0928\u094D\u0924\u0902 \u0928\u093F\u0930\u094D\u0917\u0941\u0923\u092E\u093F\u0924\u094D\u092F\u093E\u0926\u093F\u0935\u093E\u091A\u094D\u092F\u092E\u0928\u093F\u0930\u094D\u0935\u093E\u091A\u094D\u092F\u0902 \u091A\u0948\u0924\u0928\u094D\u092F\u0902 \u092C\u094D\u0930\u0939\u094D\u092E \u0965</p><p class="trans">sa hov\u0101ca mahadaha\u1E45k\u0101rap\u1E5Bthivyaptejov\u0101yv\u0101k\u0101\u015Batvena b\u1E5Bhadr\u016Bpe\u1E47\u0101\u1E47\u1E0Dako\u015Bena karmaj\xF1\u0101n\u0101rthar\u016Bpatay\u0101 bh\u0101sam\u0101namadvit\u012Byamakhilop\u0101dhivinirmukta\u1E41 tatsakala\u015Baktyupab\u1E5B\u1E41hitaman\u0101dyananta\u1E41 \u015Buddha\u1E41 \u015Biva\u1E41 \u015B\u0101nta\u1E41 nirgu\u1E47amity\u0101div\u0101cyamanirv\u0101cya\u1E41 caitanya\u1E41 brahma \u0965</p><p>\u041E\u043D \u0441\u043A\u0430\u0437\u0430\u043B: \xAB\u0411\u0440\u0430\u0445\u043C\u0430\u043D \u2014 \u044D\u0442\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0438 \u0416\u0438\u0437\u043D\u044C (\u0447\u0430\u0439\u0442\u0430\u043D\u044C\u044F). \u041E\u043D \u043D\u0435\u043E\u043F\u0438\u0441\u0443\u0435\u043C \u0438 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0411\u0435\u0441\u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 (\u043D\u0438\u0440\u0433\u0443\u043D\u0430), \u041D\u0435\u0434\u0432\u0438\u0436\u0438\u043C\u044B\u0439, \u0411\u043B\u0430\u0433\u043E\u0439 (\u0428\u0438\u0432\u0430), \u041F\u0440\u0435\u0447\u0438\u0441\u0442\u044B\u0439, \u0411\u0435\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u0439 \u0438 \u0411\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0439. \u041E\u043D \u2014 \u041F\u043E\u043B\u043D\u043E\u0442\u0430 \u0432\u0441\u0435\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439 (\u0448\u0430\u043A\u0442\u0438), \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u043E\u0442 \u043A\u0430\u043A\u0438\u0445-\u043B\u0438\u0431\u043E \u043D\u0430\u0438\u043C\u0435\u043D\u043E\u0432\u0430\u043D\u0438\u0439, [\u041E\u0434\u0438\u043D] \u0431\u0435\u0437 \u0432\u0442\u043E\u0440\u043E\u0433\u043E. [\u041E\u043D] \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u043E\u0431\u0440\u0430\u0437\u0435 [\u044D\u043D\u0435\u0440\u0433\u0438\u0439] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u044F, [\u041E\u043D \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043A\u0430\u043A \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u0438 \u043A\u0430\u043A \u044D\u0442\u043E\u0442 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439 \u043C\u0438\u0440, \u043A\u0430\u043A \u043C\u0430\u0445\u0430\u0442, \u0430\u0445\u0430\u043D\u043A\u0430\u0440\u0430, \u0437\u0435\u043C\u043B\u044F, \u0432\u043E\u0434\u0430, \u043E\u0433\u043E\u043D\u044C, \u0432\u043E\u0437\u0434\u0443\u0445 \u0438 \u044D\u0444\u0438\u0440.</p></div><div class="stanza"><a href="#s2" id="s2" class="num">2</a><p class="sans">\u0908\u0936\u094D\u0935\u0930 \u0907\u0924\u093F \u091A \u0965<br> \u092C\u094D\u0930\u0939\u094D\u092E\u0948\u0935 \u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u0902 \u092A\u094D\u0930\u0915\u0943\u0924\u094D\u092F\u092D\u093F\u0927\u0947\u092F\u093E\u092E\u093E\u0936\u094D\u0930\u093F\u0924\u094D\u092F \u0932\u094B\u0915\u093E\u0928\u094D\u0938\u0943\u0937\u094D\u091F\u094D\u0935\u093E \u092A\u094D\u0930\u0935\u093F\u0936\u094D\u092F\u093E\u0928\u094D\u0924\u0930\u094D\u092F\u093E\u092E\u093F\u0924\u094D\u0935\u0947\u0928 \u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0926\u0940\u0928\u093E\u0902 \u092C\u0941\u0926\u094D\u0927\u0940\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0928\u093F\u092F\u0928\u094D\u0924\u0943\u0924\u094D\u0935\u093E\u0926\u0940\u0936\u094D\u0935\u0930\u0903 \u0965</p><p class="trans">\u012B\u015Bvara iti ca \u0965<br> brahmaiva sva\u015Bakti\u1E41 prak\u1E5Btyabhidhey\u0101m\u0101\u015Britya lok\u0101ns\u1E5B\u1E63\u1E6Dv\u0101 pravi\u015By\u0101ntary\u0101mitvena brahm\u0101d\u012Bn\u0101\u1E41 buddh\u012Bndriyaniyant\u1E5Btv\u0101d\u012B\u015Bvara\u1E25 \u0965</p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0412\u043B\u0430\u0434\u044B\u043A\u0435 (\u0418\u0448\u0432\u0430\u0440\u0435). \u041E\u043D \u0435\u0434\u0438\u043D \u0441 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u043E\u043C; \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u0432\u043E\u0435\u0439 \u0428\u0430\u043A\u0442\u0438, \u0438\u043C\u0435\u043D\u0443\u0435\u043C\u043E\u0439 \u043F\u0440\u0430\u043A\u0440\u0438\u0442\u0438, \u041E\u043D \u0442\u0432\u043E\u0440\u0438\u0442 \u043C\u0438\u0440\u044B \u0438 \u0432\u0445\u043E\u0434\u0438\u0442 [\u0432 \u043D\u0438\u0445] \u043A\u0430\u043A \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0439 \u0412\u043B\u0430\u0434\u044B\u043A\u0430. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [\u041E\u043D] \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u0435\u0442 \u0440\u0430\u0437\u0443\u043C \u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0430 [\u0432\u0441\u0435\u0445 \u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432], \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0411\u0440\u0430\u0445\u043C\u044B, [\u041E\u043D] \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0412\u043B\u0430\u0434\u044B\u043A\u043E\u0439.</p></div><div class="stanza"><a href="#s3" id="s3" class="num">3</a><p class="sans">\u091C\u0940\u0935 \u0907\u0924\u093F \u091A \u092C\u094D\u0930\u0939\u094D\u092E\u0935\u093F\u0937\u094D\u0923\u094D\u0935\u0940\u0936\u093E\u0928\u0947\u0928\u094D\u0926\u094D\u0930\u093E\u0926\u0940\u0928\u093E\u0902 \u0928\u093E\u092E\u0930\u0942\u092A\u0926\u094D\u0935\u093E\u0930\u093E \u0938\u094D\u0925\u0942\u0932\u094B\u093D\u0939\u092E\u093F\u0924\u093F \u092E\u093F\u0925\u094D\u092F\u093E\u0927\u094D\u092F\u093E\u0938\u0935\u0936\u093E\u091C\u094D\u091C\u0940\u0935\u0903 \u0964<br> \u0938\u094B\u093D\u0939\u092E\u0947\u0915\u094B\u093D\u092A\u093F \u0926\u0947\u0939\u093E\u0930\u092E\u094D\u092D\u0915\u092D\u0947\u0926\u0935\u0936\u093E\u0926\u094D\u092C\u0939\u0941\u091C\u0940\u0935\u0903 \u0964</p><p class="trans">j\u012Bva iti ca brahmavi\u1E63\u1E47v\u012B\u015B\u0101nendr\u0101d\u012Bn\u0101\u1E41 n\u0101mar\u016Bpadv\u0101r\u0101 sth\u016Blo&#39;hamiti mithy\u0101dhy\u0101sava\u015B\u0101jj\u012Bva\u1E25 \u0964<br> so&#39;hameko&#39;pi deh\u0101rambhakabhedava\u015B\u0101dbahuj\u012Bva\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0436\u0438\u0432\u043E\u0439 \u0434\u0443\u0448\u0435 (\u0434\u0436\u0438\u0432\u0435). \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043B\u043E\u0436\u043D\u043E\u0433\u043E \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F \u0434\u0436\u0438\u0432\u0430 \u0441\u0447\u0438\u0442\u0430\u0435\u0442: \xAB\u042F \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044C\u043D\u0430\xBB \u2014 \u043F\u043E \u043F\u0440\u0438\u0447\u0438\u043D\u0435 \u0438\u043C\u0451\u043D \u0438 \u0444\u043E\u0440\u043C \u0411\u0440\u0430\u0445\u043C\u044B, \u0412\u0438\u0448\u043D\u0443, \u0418\u0448\u0430\u043D\u044B, \u0418\u043D\u0434\u0440\u044B \u0438 \u0434\u0440\u0443\u0433\u0438\u0445. \xAB\u041E\u043D\xBB (\u0442. \u0435. \u0411\u043E\u0433) \u0438 \xAB\u044F\xBB (\u0442. \u0435. \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u0430\u044F \u0434\u0443\u0448\u0430) \u0435\u0434\u0438\u043D\u044B; \u043E\u0434\u043D\u0430\u043A\u043E, \u043F\u043E \u043F\u0440\u0438\u0447\u0438\u043D\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F \u0442\u0435\u043B, \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u0436\u0438\u0432\u044B\u0445 \u0434\u0443\u0448.</p></div><div class="stanza"><a href="#s4" id="s4" class="num">4</a><p class="sans">\u092A\u094D\u0930\u0915\u0943\u0924\u093F\u0930\u093F\u0924\u093F \u091A \u092C\u094D\u0930\u0939\u094D\u092E\u0923\u0903 \u0938\u0915\u093E\u0936\u093E\u0928\u094D\u0928\u093E\u0928\u093E\u0935\u093F\u091A\u093F\u0924\u094D\u0930\u091C\u0917\u0928\u094D\u0928\u093F\u0930\u094D\u092E\u093E\u0923\u0938\u093E\u092E\u093E\u0930\u094D\u0925\u094D\u092F\u092C\u0941\u0926\u094D\u0927\u093F\u0930\u0942\u092A\u093E \u092C\u094D\u0930\u0939\u094D\u092E\u0936\u0915\u094D\u0924\u093F\u0930\u0947\u0935 \u092A\u094D\u0930\u0915\u0943\u0924\u093F\u0903 \u0964</p><p class="trans">prak\u1E5Btiriti ca brahma\u1E47a\u1E25 sak\u0101\u015B\u0101nn\u0101n\u0101vicitrajagannirm\u0101\u1E47as\u0101m\u0101rthyabuddhir\u016Bp\u0101 brahma\u015Baktireva prak\u1E5Bti\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u041F\u0440\u0438\u0440\u043E\u0434\u0435 (\u043F\u0440\u0430\u043A\u0440\u0438\u0442\u044B). \u041F\u0440\u0430\u043A\u0440\u0438\u0442\u044B \u2014 \u0441\u0438\u043B\u0430 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430, \u043E\u0431\u0440\u0430\u0437 \u0440\u0430\u0437\u0443\u043C\u0430 (\u0431\u0443\u0434\u0434\u0445\u0438), [\u043A\u043E\u0442\u043E\u0440\u0430\u044F,] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044E \u0441 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u043E\u043C, \u0442\u0432\u043E\u0440\u0438\u0442 [\u0432\u0435\u0441\u044C] \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0439 \u043C\u0438\u0440.</p></div><div class="stanza"><a href="#s5" id="s5" class="num">5</a><p class="sans">\u092A\u0930\u092E\u093E\u0924\u094D\u092E\u0947\u0924\u093F \u091A \u0926\u0947\u0939\u093E\u0926\u0947\u0903 \u092A\u0930\u0924\u0930\u0924\u094D\u0935\u0926\u094D\u092C\u094D\u0930\u093E\u0939\u094D\u092E\u0948\u0935 \u092A\u0930\u092E\u093E\u0924\u094D\u092E\u093E \u0938 \u092C\u094D\u0930\u0939\u094D\u092E\u093E \u0938 \u0935\u093F\u0937\u094D\u0923\u0941\u0903 \u0938 \u0907\u0928\u094D\u0926\u094D\u0930\u0903 \u0938 \u0936\u092E\u0928\u0903 \u0938 \u0938\u0942\u0930\u094D\u092F\u0903 \u0938 \u091A\u0928\u094D\u0926\u094D\u0930\u0938\u094D\u0924\u0947 \u0938\u0941\u0930\u093E\u0938\u094D\u0924\u0947 \u0905\u0938\u0941\u0930\u093E\u0938\u094D\u0924\u0947 \u092A\u093F\u0936\u093E\u091A\u093E\u0938\u094D\u0924\u0947 \u092E\u0928\u0941\u0937\u094D\u092F\u093E\u0938\u094D\u0924\u093E\u0903 \u0938\u094D\u0924\u094D\u0930\u093F\u092F\u0938\u094D\u0924\u0947 \u092A\u0936\u094D\u0935\u093E\u0926\u092F\u0938\u094D\u0924\u0924\u094D\u0938\u094D\u0925\u093E\u0935\u0930\u0902 \u0924\u0947 \u092C\u094D\u0930\u093E\u0939\u094D\u092E\u0923\u093E\u0926\u092F\u0903 \u0964<br> \u0938\u0930\u094D\u0935\u0902 \u0916\u0932\u094D\u0935\u093F\u0926\u0902 \u092C\u094D\u0930\u0939\u094D\u092E \u0928\u0947\u0939 \u0928\u093E\u0928\u093E\u0938\u094D\u0924\u093F \u0915\u093F\u091E\u094D\u091A\u0928 \u0964</p><p class="trans">param\u0101tmeti ca deh\u0101de\u1E25 parataratvadbr\u0101hmaiva param\u0101tm\u0101 sa brahm\u0101 sa vi\u1E63\u1E47u\u1E25 sa indra\u1E25 sa \u015Bamana\u1E25 sa s\u016Brya\u1E25 sa candraste sur\u0101ste asur\u0101ste pi\u015B\u0101c\u0101ste manu\u1E63y\u0101st\u0101\u1E25 striyaste pa\u015Bv\u0101dayastatsth\u0101vara\u1E41 te br\u0101hma\u1E47\u0101daya\u1E25 \u0964<br> sarva\u1E41 khalvida\u1E41 brahma neha n\u0101n\u0101sti ki\xF1cana \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0412\u044B\u0441\u0448\u0435\u0439 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u0438 (\u041F\u0430\u0440\u0430\u043C\u0430\u0442\u043C\u0430\u043D\u0435). [\u041F\u0430\u0440\u0430\u043C\u0430\u0442\u043C\u0430\u043D \u043D\u0430\u0437\u0432\u0430\u043D \u0442\u0430\u043A] \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E [\u043E\u043D] \u0442\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u0435\u043D \u0442\u0435\u043B\u0430\u043C; [\u043E\u043D] \u0436\u0435 \u0435\u0441\u0442\u044C \u0411\u0440\u0430\u0445\u043C\u0430\u043D. \u041E\u043D (\u0442. \u0435. \u0411\u0440\u0430\u0445\u043C\u0430\u043D, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0441\u0442\u044C \u0412\u044B\u0441\u0448\u0430\u044F \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C, \u0414\u0443\u0445) \u0435\u0441\u0442\u044C \u0411\u0440\u0430\u0445\u043C\u0430, \u041E\u043D \u0435\u0441\u0442\u044C \u0412\u0438\u0448\u043D\u0443, \u041E\u043D \u0435\u0441\u0442\u044C \u0418\u043D\u0434\u0440\u0430, \u041E\u043D \u0435\u0441\u0442\u044C [\u0431\u043E\u0433] \u0441\u043C\u0435\u0440\u0442\u0438 (\u042F\u043C\u0430), \u041E\u043D \u0435\u0441\u0442\u044C \u0421\u0443\u0440\u044C\u044F, \u041E\u043D \u0435\u0441\u0442\u044C \u0427\u0430\u043D\u0434\u0440\u0430; \u041E\u043D \u2014 \u0432\u0441\u0435 \u0431\u043E\u0433\u0438 \u0438 \u0434\u0435\u043C\u043E\u043D\u044B, \u0432\u0430\u043C\u043F\u0438\u0440\u044B, \u043C\u0443\u0436\u0447\u0438\u043D\u044B \u0438 \u0436\u0435\u043D\u0449\u0438\u043D\u044B, \u0437\u0432\u0435\u0440\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 [\u0436\u0438\u0432\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430], \u043D\u0435\u0434\u0432\u0438\u0436\u0438\u043C\u043E\u0435 (\u0441\u0442\u0445\u0430\u0432\u0430\u0440\u0430; \u0442. \u0435. \u043D\u0435\u0436\u0438\u0432\u0430\u044F \u043C\u0430\u0442\u0435\u0440\u0438\u044F), \u0431\u0440\u0430\u0445\u043C\u0430\u043D\u044B \u0438 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 [\u0442\u0440\u0438 \u0432\u0430\u0440\u043D\u044B]. \u0412\u0441\u0451 \u044D\u0442\u043E \u0435\u0441\u0442\u044C \u0411\u0440\u0430\u0445\u043C\u0430\u043D. \u0417\u0434\u0435\u0441\u044C \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439.</p></div><div class="stanza"><a href="#s6" id="s6" class="num">6</a><p class="sans">\u091C\u093E\u0924\u093F\u0930\u093F\u0924\u093F \u091A \u0964<br> \u0928 \u091A\u0930\u094D\u092E\u0923\u094B \u0928 \u0930\u0915\u094D\u0924\u0938\u094D\u092F \u0928 \u092E\u093E\u0902\u0938\u0938\u094D\u092F \u0928 \u091A\u093E\u0938\u094D\u0925\u093F\u0928\u0903 \u0964<br> \u0928 \u091C\u093E\u0924\u093F\u0930\u093E\u0924\u094D\u092E\u0928\u094B \u091C\u093E\u0924\u093F\u0930\u094D\u0935\u094D\u092F\u0935\u0939\u093E\u0930\u092A\u094D\u0930\u0915\u0932\u094D\u092A\u093F\u0924\u093E \u0964</p><p class="trans">j\u0101tiriti ca \u0964<br> na carma\u1E47o na raktasya na m\u0101\u1E41sasya na c\u0101sthina\u1E25 \u0964<br> na j\u0101tir\u0101tmano j\u0101tirvyavah\u0101raprakalpit\u0101 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u043A\u0430\u0441\u0442\u0435 (\u0434\u0436\u0430\u0442\u0438). \u041D\u0435\u0442 [\u043A\u0430\u0441\u0442\u044B] \u0443 \u043A\u043E\u0436\u0438, \u043D\u0435\u0442 \u0443 \u043A\u0440\u043E\u0432\u0438, \u043D\u0435\u0442 \u0443 \u043F\u043B\u043E\u0442\u0438, \u043D\u0435\u0442 \u0443 \u043A\u043E\u0441\u0442\u0435\u0439. \u041D\u0435\u0442 \u043A\u0430\u0441\u0442\u044B \u0443 \u0414\u0443\u0445\u0430 (\u0410\u0442\u043C\u0430\u043D\u0430). \u0412\u043E\u043E\u0431\u0440\u0430\u0436\u0430\u0435\u043C\u043E\u0435 [\u043F\u043E\u043D\u044F\u0442\u0438\u0435] \u043A\u0430\u0441\u0442\u044B [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043B\u0438\u0448\u044C] \u0438\u0437-\u0437\u0430 [\u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0440\u043E\u0434\u043E\u0432] \u0437\u0430\u043D\u044F\u0442\u0438\u0439 [\u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430].</p></div><div class="stanza"><a href="#s7" id="s7" class="num">7</a><p class="sans">\u0915\u0930\u094D\u092E\u0947\u0924\u093F \u091A \u0915\u094D\u0930\u093F\u092F\u092E\u093E\u0923\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0948\u0903 \u0915\u0930\u094D\u092E\u0923\u094D\u092F\u0939\u0902 \u0915\u0930\u094B\u092E\u0940\u0924\u094D\u092F\u0927\u094D\u092F\u093E\u0924\u094D\u092E\u0928\u093F\u0937\u094D\u0920\u0924\u092F\u093E \u0915\u0943\u0924\u0902 \u0915\u0930\u094D\u092E\u0948\u0935 \u0915\u0930\u094D\u092E \u0964</p><p class="trans">karmeti ca kriyam\u0101\u1E47endriyai\u1E25 karma\u1E47yaha\u1E41 karom\u012Btyadhy\u0101tmani\u1E63\u1E6Dhatay\u0101 k\u1E5Bta\u1E41 karmaiva karma \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0438 (\u043A\u0430\u0440\u043C\u0430). \xAB\u042F \u0434\u0435\u043B\u0430\u044E \u0442\u043E, \u0447\u0442\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u043E\u0440\u0433\u0430\u043D\u044B [\u0447\u0443\u0432\u0441\u0442\u0432 \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F]\xBB; \u0442\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u044E\u0442\u0441\u044F [\u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C,] \u0441 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0451\u043D\u043D\u043E\u0441\u0442\u044C\u044E \u0432 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u0438, [\u0435\u0441\u0442\u044C \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u0435] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F.</p></div><div class="stanza"><a href="#s8" id="s8" class="num">8</a><p class="sans">\u0905\u0915\u0930\u094D\u092E\u0947\u0924\u093F \u091A \u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u092D\u094B\u0915\u094D\u0924\u0943\u0924\u094D\u0935\u093E\u0926\u094D\u092F\u0939\u0919\u094D\u0915\u093E\u0930\u0924\u092F\u093E \u092C\u0928\u094D\u0927\u0930\u0942\u092A\u0902 \u091C\u0928\u094D\u092E\u093E\u0926\u093F\u0915\u093E\u0930\u0923\u0902 \u0928\u093F\u0924\u094D\u092F\u0928\u0948\u092E\u093F\u0924\u094D\u0924\u093F\u0915\u092F\u093E\u0917\u0935\u094D\u0930\u0924\u0924\u092A\u094B\u0926\u093E\u0928\u093E\u0926\u093F\u0937\u0941 \u092B\u0932\u093E\u092D\u093F\u0938\u0928\u094D\u0927\u093E\u0928\u0902 \u092F\u0924\u094D\u0924\u0926\u0915\u0930\u094D\u092E \u0964</p><p class="trans">akarmeti ca kart\u1E5Btvabhokt\u1E5Btv\u0101dyaha\u1E45k\u0101ratay\u0101 bandhar\u016Bpa\u1E41 janm\u0101dik\u0101ra\u1E47a\u1E41 nityanaimittikay\u0101gavratatapod\u0101n\u0101di\u1E63u phal\u0101bhisandh\u0101na\u1E41 yattadakarma \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E\u0431 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F (\u0430\u043A\u0430\u0440\u043C\u0430). \u0422\u043E, \u0447\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u0442\u0441\u044F \u0441 \u044D\u0433\u043E (\u0430\u0445\u0430\u043D\u043A\u0430\u0440\u0430), \u0441 \u043C\u044B\u0441\u043B\u044C\u044E \xAB\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C, \u044F \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0449\u0438\u0439\u0441\u044F \u0438 \u0442. \u0434.\xBB, \u0441\u0432\u044F\u0437\u044B\u0432\u0430\u0435\u0442 [\u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430] \u0438 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0439. \u0422\u0430\u043A\u0436\u0435 \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0435 (\u043D\u0438\u0442\u044C\u044F) \u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u043C\u044B\u0435 \u043F\u043E \u0441\u043B\u0443\u0447\u0430\u044E (\u043D\u0430\u0439\u043C\u0438\u0442\u0442\u0438\u043A\u0430) [\u0440\u0438\u0442\u0443\u0430\u043B\u044B, \u0442\u0430\u043A\u0438\u0435, \u043A\u0430\u043A] \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0435, \u043E\u0431\u0435\u0442\u044B, \u0430\u0441\u043A\u0435\u0437\u044B \u0438 \u043F\u043E\u0434\u0430\u044F\u043D\u0438\u0435, \u0434\u0435\u043B\u0430\u0435\u043C\u044B\u0435 \u0441 \u0436\u0435\u043B\u0430\u043D\u0438\u0435\u043C \u043D\u0430\u0433\u0440\u0430\u0434\u044B, \u0435\u0441\u0442\u044C \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 [\u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F.</p></div><div class="stanza"><a href="#s9" id="s9" class="num">9</a><p class="sans">\u091C\u094D\u091E\u093E\u0928\u092E\u093F\u0924\u093F \u091A \u0926\u0947\u0939\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0928\u093F\u0917\u094D\u0930\u0939\u0938\u0926\u094D\u0917\u0941\u0930\u0942\u092A\u093E\u0938\u0928\u0936\u094D\u0930\u0935\u0923\u092E\u0928\u0928\u0928\u093F\u0926\u093F\u0927\u094D\u092F\u093E\u0938\u0928\u0948\u0930\u094D\u092F\u0926\u094D\u092F\u0926\u0943\u0917\u094D\u0926\u0943\u0936\u094D\u092F\u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u0938\u0930\u094D\u0935\u093E\u0928\u094D\u0924\u0930\u0938\u094D\u0925\u0902 \u0938\u0930\u094D\u0935\u0938\u092E\u0902 \u0918\u091F\u092A\u091F\u093E\u0926\u093F\u092A\u0926\u093E\u0930\u094D\u0925\u092E\u093F\u0935\u093E\u0935\u093F\u0915\u093E\u0930\u0902 \u0935\u093F\u0915\u093E\u0930\u0947\u0937\u0941 \u091A\u0948\u0924\u0928\u094D\u092F\u0902 \u0935\u093F\u0928\u093E \u0915\u093F\u091E\u094D\u091A\u093F\u0928\u094D\u0928\u093E\u0938\u094D\u0924\u0940\u0924\u093F \u0938\u093E\u0915\u094D\u0936\u093E\u0924\u094D\u0915\u093E\u0930\u093E\u0928\u0941\u092D\u0935\u094B \u091C\u094D\u091E\u093E\u0928\u092E\u094D \u0964</p><p class="trans">j\xF1\u0101namiti ca dehendriyanigrahasadgur\u016Bp\u0101sana\u015Brava\u1E47amanananididhy\u0101sanairyadyad\u1E5Bgd\u1E5B\u015Byasvar\u016Bpa\u1E41 sarv\u0101ntarastha\u1E41 sarvasama\u1E41 gha\u1E6Dapa\u1E6D\u0101dipad\u0101rthamiv\u0101vik\u0101ra\u1E41 vik\u0101re\u1E63u caitanya\u1E41 vin\u0101 ki\xF1cinn\u0101st\u012Bti s\u0101k\u015B\u0101tk\u0101r\u0101nubhavo j\xF1\u0101nam \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0437\u043D\u0430\u043D\u0438\u0438 (\u0434\u0436\u043D\u044F\u043D\u0430). [\u0418\u0441\u0442\u0438\u043D\u043D\u043E\u0435] \u0437\u043D\u0430\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0447\u0430\u0439\u0442\u0430\u043D\u044C\u044F), \u043F\u043E\u043C\u0438\u043C\u043E \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435\u0442; \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u043E \u0432\u0441\u0435\u0445 \u0432\u0438\u0434\u043E\u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F\u0445 [\u043C\u0430\u0442\u0435\u0440\u0438\u0438], \u0432\u043E \u0432\u0441\u0435\u0445 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u0445 \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u044B\u043C. [\u042D\u0442\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0435\u0441\u0442\u044C] \u0438\u0441\u0442\u0438\u043D\u043D\u0430\u044F \u0444\u043E\u0440\u043C\u0430 (\u0441\u0432\u0430\u0440\u0443\u043F\u0430) \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u0430, [\u043E\u043D\u043E] \u0440\u0430\u0432\u043D\u043E \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u043E \u0432\u0441\u0435\u043C [\u0441\u0443\u0449\u0435\u043C]. [\u041F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0442\u0435\u043B\u0430 \u0438 \u043E\u0440\u0433\u0430\u043D\u043E\u0432 [\u0447\u0443\u0432\u0441\u0442\u0432 \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F], \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u043C\u0443 \u0443\u0447\u0438\u0442\u0435\u043B\u044E \u0438 [\u0434\u0436\u043D\u044F\u043D\u0430-\u0439\u043E\u0433\u0438:] \u0441\u043B\u0443\u0448\u0430\u043D\u0438\u044F (\u0448\u0440\u0430\u0432\u0430\u043D\u0430), \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F (\u043C\u0430\u043D\u0430\u043D\u0430) \u0438 \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u0438 (\u043D\u0438\u0434\u0438\u0434\u0445\u044C\u044F\u0441\u0430\u043D\u0430).</p></div><div class="stanza"><a href="#s10" id="s10" class="num">10</a><p class="sans">\u0905\u091C\u094D\u091E\u093E\u0928\u092E\u093F\u0924\u093F \u091A \u0930\u091C\u094D\u091C\u094C \u0938\u0930\u094D\u092A\u092D\u094D\u0930\u093E\u0928\u094D\u0924\u093F\u0930\u093F\u0935\u093E\u0926\u094D\u0935\u093F\u0924\u0940\u092F\u0947 \u0938\u0930\u094D\u0935\u093E\u0928\u0941\u0938\u094D\u092F\u0942\u0924\u0947 \u0938\u0930\u094D\u0935\u092E\u092F\u0947 \u092C\u094D\u0930\u0939\u094D\u092E\u0923\u093F \u090F\u0935\u0924\u093F\u0930\u094D\u092F\u0919\u094D\u0928\u0930\u0938\u094D\u0925\u093E\u0935\u0930\u0938\u094D\u0924\u094D\u0930\u0940\u092A\u0941\u0930\u0941\u0937\u0935\u0930\u094D\u0923\u093E\u0936\u094D\u0930\u092E\u092C\u0928\u094D\u0927\u092E\u094B\u0915\u094D\u0936\u094B\u092A\u093E\u0927\u093F\u0928\u093E\u0928\u093E\u0924\u094D\u092E\u092D\u0947\u0926\u0915\u0932\u094D\u092A\u093F\u0924 \u091C\u094D\u091E\u093E\u0928\u092E\u091C\u094D\u091E\u093E\u0928\u092E\u094D \u0964</p><p class="trans">aj\xF1\u0101namiti ca rajjau sarpabhr\u0101ntiriv\u0101dvit\u012Bye sarv\u0101nusy\u016Bte sarvamaye brahma\u1E47i evatirya\u1E45narasth\u0101varastr\u012Bpuru\u1E63avar\u1E47\u0101\u015Bramabandhamok\u015Bop\u0101dhin\u0101n\u0101tmabhedakalpita j\xF1\u0101namaj\xF1\u0101nam \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u043D\u0435\u0437\u043D\u0430\u043D\u0438\u0438 (\u0430\u0434\u0436\u043D\u044F\u043D\u0430). \u041D\u0435\u0437\u043D\u0430\u043D\u0438\u0435 \u2014 \u044D\u0442\u043E \u043B\u043E\u0436\u043D\u043E\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u0432 \u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435\u043C \u043D\u0435\u0434\u0435\u043B\u0438\u043C\u043E\u043C \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0435 \u0432\u043E\u043E\u0431\u0440\u0430\u0436\u0430\u0435\u043C\u044B\u0445 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0445 \xAB\u0431\u043E\u0433\u0438 \u0438 \u043B\u044E\u0434\u0438, \u043D\u0435\u0436\u0438\u0432\u0430\u044F \u043C\u0430\u0442\u0435\u0440\u0438\u044F, \u0436\u0435\u043D\u0449\u0438\u043D\u044B \u0438 \u043C\u0443\u0436\u0447\u0438\u043D\u044B, \u043A\u0430\u0441\u0442\u044B \u0438 \u0441\u0442\u0430\u0434\u0438\u0438 \u0436\u0438\u0437\u043D\u0438 (\u0432\u0430\u0440\u043D\u0430\u0448\u0440\u0430\u043C\u0430), \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435\xBB. [\u042D\u0442\u043E \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443,] \u043A\u0430\u043A \u0432\u0435\u0440\u0451\u0432\u043A\u0443 [\u043F\u043E \u043E\u0448\u0438\u0431\u043A\u0435 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442] \u0437\u0430 \u0437\u043C\u0435\u044E.</p></div><div class="stanza"><a href="#s11" id="s11" class="num">11</a><p class="sans">\u0938\u0941\u0916\u092E\u093F\u0924\u093F \u091A \u0938\u091A\u094D\u091A\u093F\u0926\u093E\u0928\u0928\u094D\u0926\u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u091C\u094D\u091E\u093E\u0924\u094D\u0935\u093E\u0928\u0928\u094D\u0926\u0930\u0942\u092A\u093E \u092F\u093E \u0938\u094D\u0925\u093F\u0924\u093F\u0903 \u0938\u0948\u0935 \u0938\u0941\u0916\u092E\u094D \u0964</p><p class="trans">sukhamiti ca saccid\u0101nandasvar\u016Bpa\u1E41 j\xF1\u0101tv\u0101nandar\u016Bp\u0101 y\u0101 sthiti\u1E25 saiva sukham \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0441\u0447\u0430\u0441\u0442\u044C\u0435 (\u0441\u0443\u043A\u0445\u0430). \u0421\u0447\u0430\u0441\u0442\u044C\u0435 \u2014 \u044D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430, [\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0435] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044E \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B (\u0441\u0432\u0430\u0440\u0443\u043F\u0430) \u0411\u044B\u0442\u0438\u044F, \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430.</p></div><div class="stanza"><a href="#s12" id="s12" class="num">12</a><p class="sans">\u0926\u0941\u0903\u0916\u092E\u093F\u0924\u093F \u0905\u0928\u093E\u0924\u094D\u092E\u0930\u0942\u092A\u0903 \u0935\u093F\u0937\u092F\u0938\u0919\u094D\u0915\u0932\u094D\u092A \u090F\u0935 \u0926\u0941\u0903\u0916\u092E\u094D \u0964</p><p class="trans">du\u1E25khamiti an\u0101tmar\u016Bpa\u1E25 vi\u1E63ayasa\u1E45kalpa eva du\u1E25kham \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u043D\u0435\u0441\u0447\u0430\u0441\u0442\u044C\u0435 (\u0434\u0443\u043A\u043A\u0445\u0430). \u0424\u043E\u0440\u043C\u0430, \u043B\u0438\u0448\u0451\u043D\u043D\u0430\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438, \u0438 \u0436\u0435\u043B\u0430\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 [\u0432\u043C\u0435\u0441\u0442\u043E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438] \u0435\u0441\u0442\u044C \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0435.</p></div><div class="stanza"><a href="#s13" id="s13" class="num">13</a><p class="sans">\u0938\u094D\u0935\u0930\u094D\u0917 \u0907\u0924\u093F \u091A \u0938\u0924\u094D\u0938\u0902\u0938\u0930\u094D\u0917\u0903 \u0938\u094D\u0935\u0930\u094D\u0917\u0903 \u0964</p><p class="trans">svarga iti ca satsa\u1E41sarga\u1E25 svarga\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0440\u0430\u0435. \u0418\u0441\u0442\u0438\u043D\u043D\u043E\u0435 \u043E\u0431\u0449\u0435\u043D\u0438\u0435 \u0435\u0441\u0442\u044C \u0440\u0430\u0439.</p></div><div class="stanza"><a href="#s14" id="s14" class="num">14</a><p class="sans">\u0928\u0930\u0915 \u0907\u0924\u093F \u091A \u0905\u0938\u0924\u094D\u0938\u0902\u0938\u093E\u0930\u0935\u093F\u0937\u092F\u091C\u0928\u0938\u0902\u0938\u0930\u094D\u0917 \u090F\u0935 \u0928\u0930\u0915\u0903 \u0964</p><p class="trans">naraka iti ca asatsa\u1E41s\u0101ravi\u1E63ayajanasa\u1E41sarga eva naraka\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E\u0431 \u0430\u0434\u0435. \u041E\u0431\u0449\u0435\u043D\u0438\u0435 \u0441 \u043B\u044E\u0434\u044C\u043C\u0438, [\u043A\u043E\u0442\u043E\u0440\u044B\u0435] \u043D\u0435 [\u0432\u0435\u0434\u0430\u044E\u0442] \u0438\u0441\u0442\u0438\u043D\u044B [\u0438 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u0443\u044E\u0442\u0441\u044F \u043B\u0438\u0448\u044C] \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438 \u044D\u0442\u043E\u0433\u043E \u043C\u0438\u0440\u0430, \u0435\u0441\u0442\u044C \u0430\u0434.</p></div><div class="stanza"><a href="#s15" id="s15" class="num">15</a><p class="sans">\u092C\u0928\u094D\u0927 \u0907\u0924\u093F \u091A \u0905\u0928\u093E\u0926\u094D\u092F\u0935\u093F\u0926\u094D\u092F\u093E\u0935\u093E\u0938\u0928\u092F\u093E \u091C\u093E\u0924\u094B\u093D\u0939\u092E\u093F\u0924\u094D\u092F\u093E\u0926\u093F\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u092A\u093F\u0924\u0943\u092E\u093E\u0924\u0943\u0938\u0939\u094B\u0926\u0930\u0926\u093E\u0930\u093E\u092A\u0924\u094D\u092F\u0917\u0943\u0939\u093E\u0930\u093E\u092E\u0915\u094D\u0936\u0947\u0924\u094D\u0930\u092E\u092E\u0924\u093E \u0938\u0902\u0938\u093E\u0930\u093E\u0935\u0930\u0923\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u093E\u0926\u094D\u092F\u0939\u0919\u094D\u0915\u093E\u0930\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u0905\u0923\u093F\u092E\u093E\u0926\u094D\u092F\u0937\u094D\u091F\u0948\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0936\u093E\u0938\u093F\u0926\u094D\u0927\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u0926\u0947\u0935\u092E\u0928\u0941\u0937\u094D\u092F\u093E\u0926\u094D\u092F\u0941\u092A\u093E\u0938\u0928\u093E\u0915\u093E\u092E\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u092F\u092E\u093E\u0926\u094D\u092F\u0937\u094D\u091F\u093E\u0919\u094D\u0917\u092F\u094B\u0917\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u0935\u0930\u094D\u0923\u093E\u0936\u094D\u0930\u092E\u0927\u0930\u094D\u092E\u0915\u0930\u094D\u092E\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u0906\u091C\u094D\u091E\u093E\u092D\u092F\u0938\u0902\u0936\u092F\u093E\u0924\u094D\u092E\u0917\u0941\u0923\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u092F\u093E\u0917\u0935\u094D\u0930\u0924\u0924\u092A\u094B\u0926\u093E\u0928\u0935\u093F\u0927\u093F\u0935\u093F\u0927\u093E\u0928\u091C\u094D\u091E\u093E\u0928\u0938\u092E\u094D\u092D\u0935\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u0915\u0947\u0935\u0932\u092E\u094B\u0915\u094D\u0936\u093E\u092A\u0947\u0915\u094D\u0936\u093E\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u094B \u092C\u0928\u094D\u0927\u0903 \u0964<br> \u0938\u0919\u094D\u0915\u0932\u094D\u092A\u092E\u093E\u0924\u094D\u0930\u0938\u0902\u092D\u0935\u094B \u092C\u0928\u094D\u0927\u0903 \u0964</p><p class="trans">bandha iti ca an\u0101dyavidy\u0101v\u0101sanay\u0101 j\u0101to&#39;hamity\u0101disa\u1E45kalpo bandha\u1E25 \u0964<br> pit\u1E5Bm\u0101t\u1E5Bsahodarad\u0101r\u0101patyag\u1E5Bh\u0101r\u0101mak\u015Betramamat\u0101 sa\u1E41s\u0101r\u0101vara\u1E47asa\u1E45kalpo bandha\u1E25 \u0964<br> kart\u1E5Btv\u0101dyaha\u1E45k\u0101rasa\u1E45kalpo bandha\u1E25 \u0964<br> a\u1E47im\u0101dya\u1E63\u1E6Dai\u015Bvary\u0101\u015B\u0101siddhasa\u1E45kalpo bandha\u1E25 \u0964<br> devamanu\u1E63y\u0101dyup\u0101san\u0101k\u0101masa\u1E45kalpo bandha\u1E25 \u0964<br> yam\u0101dya\u1E63\u1E6D\u0101\u1E45gayogasa\u1E45kalpo bandha\u1E25 \u0964<br> var\u1E47\u0101\u015Bramadharmakarmasa\u1E45kalpo bandha\u1E25 \u0964<br> \u0101j\xF1\u0101bhayasa\u1E41\u015Bay\u0101tmagu\u1E47asa\u1E45kalpo bandha\u1E25 \u0964<br> y\u0101gavratatapod\u0101navidhividh\u0101naj\xF1\u0101nasambhavo bandha\u1E25 \u0964<br> kevalamok\u015B\u0101pek\u015B\u0101sa\u1E45kalpo bandha\u1E25 \u0964<br> sa\u1E45kalpam\u0101trasa\u1E41bhavo bandha\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 (\u0431\u0430\u043D\u0434\u0445\u0435). \u0421\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u0435\u0441\u0442\u044C \u043C\u044B\u0441\u043B\u0438 \u2014 \xAB\u042F \u0440\u043E\u0436\u0434\u0451\u043D\xBB \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u2014 [\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0435] \u0432\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435 [\u043F\u0440\u0438\u0441\u0443\u0449\u0435\u0439 \u0443\u043C\u0443] \u0442\u0435\u043D\u0434\u0435\u043D\u0446\u0438\u0438 (\u0432\u0430\u0441\u0430\u043D\u0430) \u2013 \u0431\u0435\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0430\u0432\u0438\u0434\u044C\u0438 (\u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F). \u0412\u043E\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u043E\u0433\u0440\u0430\u0434\u044B [\u0432\u043E\u043A\u0440\u0443\u0433 \u043A\u0430\u043A\u043E\u0433\u043E-\u043B\u0438\u0431\u043E \u0443\u0447\u0430\u0441\u0442\u043A\u0430] \u044D\u0442\u043E\u0433\u043E \u043C\u0438\u0440\u0430, [\u0432\u043E\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E] \u043E\u0442\u0435\u0446, \u043C\u0430\u0442\u044C, \u0431\u0440\u0430\u0442\u044C\u044F \u0438 \u0441\u0451\u0441\u0442\u0440\u044B, \u0436\u0451\u043D\u044B \u0438 \u043C\u0443\u0436\u044C\u044F, \u0434\u043E\u043C\u0430, \u0441\u0430\u0434\u044B \u0438 \u043F\u043E\u043B\u044F \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0442 \u043D\u0430\u043C (\u0442\u043E \u0435\u0441\u0442\u044C \u043D\u0430\u0448\u0435\u043C\u0443 \u044D\u0433\u043E), \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C. \u042D\u0433\u043E\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0438\u0434\u0435\u0438, \u0442\u0430\u043A\u0438\u0435, \u043A\u0430\u043A [\u0432\u043E\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u0441\u0435\u0431\u044F] \u0434\u0435\u044F\u0442\u0435\u043B\u0435\u043C, \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C. \u0421\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0432\u043E\u0441\u0435\u043C\u044C \u0432\u0438\u0434\u043E\u0432 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u2014 \u0430\u043D\u0438\u043C\u0430 \u0438 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u2014 \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C. \u0421\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C \u0431\u043E\u0433\u043E\u0432 \u0438 \u043B\u044E\u0434\u0435\u0439 \u0440\u0430\u0434\u0438 [\u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F \u0441\u0432\u043E\u0438\u0445] \u0436\u0435\u043B\u0430\u043D\u0438\u0439 \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C. \u0416\u0435\u043B\u0430\u043D\u0438\u0435 [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C] \u0432\u043E\u0441\u044C\u043C\u0438\u0447\u043B\u0435\u043D\u043D\u0443\u044E \u0439\u043E\u0433\u0443, \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0443\u044E\u0441\u044F \u0441 \u0441\u0430\u043C\u043E\u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044F (\u044F\u043C\u0430), \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C. \u0421\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u043F\u0440\u0435\u0434\u043F\u0438\u0441\u0430\u043D\u0438\u044F\u043C\u0438 \u043A\u0430\u0441\u0442 \u0438 \u0441\u0442\u0443\u043F\u0435\u043D\u0435\u0439 \u0436\u0438\u0437\u043D\u0438 (\u0432\u0430\u0440\u043D\u0430\u0448\u0440\u0430\u043C\u0430) \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C. \u0412\u043E\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0414\u0443\u0445 (\u0410\u0442\u043C\u0430\u043D) \u0438\u043C\u0435\u0435\u0442 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430, \u0442\u0430\u043A\u0438\u0435, \u043A\u0430\u043A \u0436\u0435\u043B\u0430\u043D\u0438\u0435 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0441\u0442\u0440\u0430\u0445 \u0438 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0435, \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C. [\u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u0435] \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0439, [\u043F\u0440\u0438\u043D\u044F\u0442\u0438\u0435 \u0440\u0435\u043B\u0438\u0433\u0438\u043E\u0437\u043D\u044B\u0445] \u043E\u0431\u0435\u0442\u043E\u0432, \u0430\u0441\u043A\u0435\u0442\u0438\u0437\u043C \u0438 \u0440\u0430\u0437\u0434\u0430\u0447\u0430 [\u043C\u0438\u043B\u043E\u0441\u0442\u044B\u043D\u0438] \u2014 \u0432\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435 \u0437\u043D\u0430\u043D\u0438\u044F \u043F\u0440\u0435\u0434\u043F\u0438\u0441\u0430\u043D\u0438\u0439 [\u0448\u0430\u0441\u0442\u0440 \u0438 \u0438\u0445 \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F] \u2014 \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C. [\u0416\u0438\u0437\u043D\u044C] \u0441 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0438\u0434\u0435\u0435\u0439 \u2014 \u043D\u0430\u0434\u0435\u0436\u0434\u043E\u0439 \u043D\u0430 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u2014 \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C. \u0421\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0438\u0437 \u0432\u043E\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u0438 \u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0439 \u0443\u043C\u0430 (\u0441\u0430\u043D\u043A\u0430\u043B\u044C\u043F\u0430).</p></div><div class="stanza"><a href="#s16" id="s16" class="num">16</a><p class="sans">\u092E\u094B\u0915\u094D\u0936 \u0907\u0924\u093F \u091A \u0928\u093F\u0924\u094D\u092F\u093E\u0928\u093F\u0924\u094D\u092F\u0935\u0938\u094D\u0924\u0941\u0935\u093F\u091A\u093E\u0930\u093E\u0926\u0928\u093F\u0924\u094D\u092F\u0938\u0902\u0938\u093E\u0930\u0938\u0941\u0916\u0926\u0941\u0903\u0916\u0935\u093F\u0937\u092F\u0938\u092E\u0938\u094D\u0924\u0915\u094D\u0936\u0947\u0924\u094D\u0930\u092E\u092E\u0924\u093E\u092C\u0928\u094D\u0927\u0915\u094D\u0936\u092F\u094B \u092E\u094B\u0915\u094D\u0936\u0903 \u0964</p><p class="trans">mok\u015Ba iti ca nity\u0101nityavastuvic\u0101r\u0101danityasa\u1E41s\u0101rasukhadu\u1E25khavi\u1E63ayasamastak\u015Betramamat\u0101bandhak\u015Bayo mok\u015Ba\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E\u0431 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0438. \u0423\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u0435 \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 (\u0431\u0430\u043D\u0434\u0445\u0430) [\u0438\u0434\u0435\u0435\u0439 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E] \u0432\u0441\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u044B \u044D\u0442\u043E\u0433\u043E \u043C\u0438\u0440\u0430, \u043F\u0440\u0438\u0447\u0438\u043D\u044F\u044E\u0449\u0438\u0435 \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435 \u0438 \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0435, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0442 [\u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0443], [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0435] \u0432\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u044F \u0432\u0435\u0447\u043D\u043E\u0433\u043E \u0438 \u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E, \u0435\u0441\u0442\u044C \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435.</p></div><div class="stanza"><a href="#s17" id="s17" class="num">17</a><p class="sans">\u0909\u092A\u093E\u0938\u094D\u092F \u0907\u0924\u093F \u091A \u0938\u0930\u094D\u0935\u0936\u0930\u0940\u0930\u0938\u094D\u0925\u091A\u0948\u0924\u0928\u094D\u092F\u092C\u094D\u0930\u0939\u094D\u092E\u092A\u094D\u0930\u093E\u092A\u0915\u094B \u0917\u0941\u0930\u0941\u0930\u0941\u092A\u093E\u0938\u094D\u092F\u0903 \u0964</p><p class="trans">up\u0101sya iti ca sarva\u015Bar\u012Brasthacaitanyabrahmapr\u0101pako gururup\u0101sya\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0442\u043E\u043C, \u043A\u043E\u0433\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C. \u0422\u043E\u0433\u043E \u0443\u0447\u0438\u0442\u0435\u043B\u044F (\u0413\u0443\u0440\u0443), \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u043E\u043C\u043E\u0433\u0430\u0435\u0442 [\u0443\u0447\u0435\u043D\u0438\u043A\u0443] \u043F\u043E\u0441\u0442\u0438\u0447\u044C \u0411\u0440\u0430\u0445\u043C\u0430\u043D, \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 \u0432\u043E \u0432\u0441\u0435\u0445 \u0442\u0435\u043B\u0430\u0445 \u043A\u0430\u043A \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0438 \u0416\u0438\u0437\u043D\u044C (\u0447\u0430\u0439\u0442\u0430\u043D\u044C\u044F), \u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u043F\u043E\u0447\u0438\u0442\u0430\u0442\u044C [\u0438 \u0435\u043C\u0443 \u0441\u0442\u043E\u0438\u0442 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u044C].</p></div><div class="stanza"><a href="#s18" id="s18" class="num">18</a><p class="sans">\u0936\u093F\u0937\u094D\u092F \u0907\u0924\u093F \u091A \u0935\u093F\u0926\u094D\u092F\u093E\u0927\u094D\u0935\u0938\u094D\u0924\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u093E\u0935\u0917\u093E\u0939\u093F\u0924\u091C\u094D\u091E\u093E\u0928\u093E\u0935\u0936\u093F\u0937\u094D\u091F\u0902 \u092C\u094D\u0930\u0939\u094D\u092E\u0948\u0935 \u0936\u093F\u0937\u094D\u092F\u0903 \u0964</p><p class="trans">\u015Bi\u1E63ya iti ca vidy\u0101dhvastaprapa\xF1c\u0101vag\u0101hitaj\xF1\u0101n\u0101va\u015Bi\u1E63\u1E6Da\u1E41 brahmaiva \u015Bi\u1E63ya\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E\u0431 \u0443\u0447\u0435\u043D\u0438\u043A\u0435. \u0423\u0447\u0435\u043D\u0438\u043A \u0435\u0441\u0442\u044C \u0432\u043E\u0438\u0441\u0442\u0438\u043D\u0443 \u0411\u0440\u0430\u0445\u043C\u0430\u043D, \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u043D\u044B\u0439 \u0432 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043C\u0438\u0440\u0430 \u043A\u0430\u043A \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0438\u043B\u043E\u0439 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F.</p></div><div class="stanza"><a href="#s19" id="s19" class="num">19</a><p class="sans">\u0935\u093F\u0926\u094D\u0935\u093E\u0928\u093F\u0924\u093F \u091A \u0938\u0930\u094D\u0935\u093E\u0928\u094D\u0924\u0930\u0938\u094D\u0925\u0938\u094D\u0935\u0938\u0902\u0935\u093F\u0926\u094D\u0930\u0942\u092A\u0935\u093F\u0926\u094D\u0935\u093F\u0926\u094D\u0935\u093E\u0928\u094D \u0964</p><p class="trans">vidv\u0101niti ca sarv\u0101ntarasthasvasa\u1E41vidr\u016Bpavidvidv\u0101n \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u043F\u043E\u0437\u043D\u0430\u0432\u0448\u0435\u043C. \u0422\u043E\u0442, \u043A\u0442\u043E \u043F\u043E\u0441\u0442\u0438\u0433 \u0444\u043E\u0440\u043C\u0443 \u0441\u0432\u043E\u0435\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0441\u0432\u0430\u0441\u0430\u043C\u0432\u0438\u0434\u0440\u0443\u043F\u0443), \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0443\u044E \u0432\u043D\u0443\u0442\u0440\u0438 \u0432\u0441\u0435\u0433\u043E, \u0435\u0441\u0442\u044C \u043F\u043E\u0437\u043D\u0430\u0432\u0448\u0438\u0439.</p></div><div class="stanza"><a href="#s20" id="s20" class="num">20</a><p class="sans">\u092E\u0942\u0922 \u0907\u0924\u093F \u091A \u0915\u0930\u094D\u0924\u0943\u0924\u094D\u0935\u093E\u0926\u094D\u092F\u0939\u0919\u094D\u0915\u093E\u0930\u092D\u093E\u0935\u093E\u0930\u0942\u0922\u094B \u092E\u0942\u0922\u0903 \u0964</p><p class="trans">m\u016B\u1E0Dha iti ca kart\u1E5Btv\u0101dyaha\u1E45k\u0101rabh\u0101v\u0101r\u016B\u1E0Dho m\u016B\u1E0Dha\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E [\u0442\u043E\u043C, \u043A\u0442\u043E \u0435\u0441\u0442\u044C] \u0433\u043B\u0443\u043F\u0435\u0446. \u0422\u043E\u0442, \u043A\u0442\u043E \u0432\u043E\u0441\u0441\u0435\u0434\u0430\u0435\u0442 \u043D\u0430 \u0447\u0443\u0432\u0441\u0442\u0432\u0435 [\u0441\u0432\u043E\u0435\u0433\u043E] \u044D\u0433\u043E (\u0430\u0445\u0430\u043D\u043A\u0430\u0440\u0435), [\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u043C\u0441\u044F \u043A\u0430\u043A \u0438\u0434\u0435\u044F] \xAB\u042F [\u0435\u0441\u0442\u044C \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u0439] \u0434\u0435\u044F\u0442\u0435\u043B\u044C\xBB \u0438 \u0442. \u0434., \u0435\u0441\u0442\u044C \u0433\u043B\u0443\u043F\u0435\u0446.</p></div><div class="stanza"><a href="#s21" id="s21" class="num">21</a><p class="sans">\u0906\u0938\u0941\u0930\u092E\u093F\u0924\u093F \u091A \u092C\u094D\u0930\u0939\u094D\u092E\u0935\u093F\u0937\u094D\u0923\u094D\u0935\u0940\u0936\u093E\u0928\u0947\u0928\u094D\u0926\u094D\u0930\u093E\u0926\u0940\u0928\u093E\u092E\u0948\u0936\u094D\u0935\u0930\u094D\u092F\u0915\u093E\u092E\u0928\u092F\u093E \u0928\u093F\u0930\u0936\u0928\u091C\u092A\u093E\u0917\u094D\u0928\u093F\u0939\u094B\u0924\u094D\u0930\u093E\u0926\u093F\u0937\u094D\u0935\u0928\u094D\u0924\u0930\u093E\u0924\u094D\u092E\u093E\u0928\u0902 \u0938\u0928\u094D\u0924\u093E\u092A\u092F\u0924\u093F \u091A\u093E\u0924\u094D\u092F\u0941\u0917\u094D\u0930\u0930\u093E\u0917\u0926\u094D\u0935\u0947\u0937\u0935\u093F\u0939\u093F\u0902\u0938\u093E \u0926\u092E\u094D\u092D\u093E\u0926\u094D\u092F\u092A\u0947\u0915\u094D\u0936\u093F\u0924\u0902 \u0924\u092A \u0906\u0938\u0941\u0930\u092E\u094D \u0964</p><p class="trans">\u0101suramiti ca brahmavi\u1E63\u1E47v\u012B\u015B\u0101nendr\u0101d\u012Bn\u0101mai\u015Bvaryak\u0101manay\u0101 nira\u015Banajap\u0101gnihotr\u0101di\u1E63vantar\u0101tm\u0101na\u1E41 sant\u0101payati c\u0101tyugrar\u0101gadve\u1E63avihi\u1E41s\u0101 dambh\u0101dyapek\u015Bita\u1E41 tapa \u0101suram \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0442\u043E\u043C, \u0447\u0442\u043E \u0434\u0435\u043C\u043E\u043D\u0438\u0447\u043D\u043E. \u0414\u0435\u043C\u043E\u043D\u0438\u0447\u043D\u0430 \u0430\u0441\u043A\u0435\u0437\u0430, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0430\u044F \u0438\u0437 \u043D\u0430\u0441\u0438\u043B\u044C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0442\u0440\u0430\u0441\u0442\u0438, \u0432\u0440\u0430\u0436\u0434\u0435\u0431\u043D\u043E\u0441\u0442\u0438, [\u0436\u0435\u043B\u0430\u043D\u0438\u044F] \u043D\u0430\u0441\u0438\u043B\u0438\u044F, \u043B\u0438\u0446\u0435\u043C\u0435\u0440\u0438\u044F \u0438 \u0442. \u043F.; [\u0434\u0435\u043C\u043E\u043D\u0438\u0447\u043D\u044B \u0442\u0430\u043A\u0438\u0435] \u043F\u043E\u0441\u0442\u044B, \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u0435 [\u043C\u0430\u043D\u0442\u0440], \u043E\u0433\u043D\u0435\u043D\u043D\u044B\u0435 \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 [\u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438], [\u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u043C\u044B\u0435] \u0441\u043E \u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435\u043C [\u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C] \u0432\u043B\u0430\u0441\u0442\u044C, [\u043F\u043E\u0434\u043E\u0431\u043D\u0443\u044E \u0432\u043B\u0430\u0441\u0442\u0438 \u0431\u043E\u0433\u043E\u0432:] \u0411\u0440\u0430\u0445\u043C\u044B, \u0412\u0438\u0448\u043D\u0443, \u0418\u0448\u0430\u043D\u044B, \u0418\u043D\u0434\u0440\u044B \u0438 \u0434\u0440\u0443\u0433\u0438\u0445. [\u042D\u0442\u0438\u043C \u0447\u0435\u043B\u043E\u0432\u0435\u043A] \u043C\u0443\u0447\u0430\u0435\u0442 [\u0441\u0432\u043E\u044E] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C.</p></div><div class="stanza"><a href="#s22" id="s22" class="num">22</a><p class="sans">\u0924\u092A \u0907\u0924\u093F \u091A \u092C\u094D\u0930\u0939\u094D\u092E \u0938\u0924\u094D\u092F\u0902 \u091C\u0917\u0928\u094D\u092E\u093F\u0925\u094D\u092F\u0947\u0924\u094D\u092F\u092A\u0930\u094B\u0915\u094D\u0936\u091C\u094D\u091E\u093E\u0928\u093E\u0917\u094D\u0928\u093F\u0928\u093E \u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0926\u094D\u092F\u0948\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0936\u093E\u0938\u093F\u0926\u094D\u0927\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u092C\u0940\u091C\u0938\u0928\u094D\u0924\u093E\u092A\u0902 \u0924\u092A\u0903 \u0964</p><p class="trans">tapa iti ca brahma satya\u1E41 jaganmithyetyaparok\u015Baj\xF1\u0101n\u0101gnin\u0101 brahm\u0101dyai\u015Bvary\u0101\u015B\u0101siddhasa\u1E45kalpab\u012Bjasant\u0101pa\u1E41 tapa\u1E25 \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u043F\u043E\u0434\u0432\u0438\u0436\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u0435 (\u0442\u0430\u043F\u0430\u0441). \u041F\u043E\u0434\u0432\u0438\u0436\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0435\u0441\u0442\u044C \u0441\u0436\u0438\u0433\u0430\u043D\u0438\u0435 [\u0432 \u0441\u0435\u0431\u0435] \u0441\u0435\u043C\u0435\u043D\u0438 \u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u044F \u043A \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044E \u0432\u043B\u0430\u0441\u0442\u0438, [\u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0439 \u0432\u043B\u0430\u0441\u0442\u0438 \u0431\u043E\u0433\u043E\u0432 \u2014] \u0411\u0440\u0430\u0445\u043C\u044B \u0438 \u0434\u0440\u0443\u0433\u0438\u0445, \u0432 \u043E\u0433\u043D\u0435 \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \xAB\u0411\u0440\u0430\u0445\u043C\u0430\u043D \u0438\u0441\u0442\u0438\u043D\u0435\u043D, [\u0430 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435] \u043C\u0438\u0440\u0430 [\u043A\u0430\u043A \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043E\u0442 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430] \u0438\u043B\u043B\u044E\u0437\u043E\u0440\u043D\u043E\xBB.</p></div><div class="stanza"><a href="#s23" id="s23" class="num">23</a><p class="sans">\u092A\u0930\u092E\u0902 \u092A\u0926\u092E\u093F\u0924\u093F \u091A \u092A\u094D\u0930\u093E\u0923\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0926\u094D\u092F\u0928\u094D\u0924\u0903\u0915\u0930\u0923\u0917\u0941\u0923\u093E\u0926\u0947\u0903 \u092A\u0930\u0924\u0930\u0902 \u0938\u091A\u094D\u091A\u093F\u0926\u093E\u0928\u0928\u094D\u0926\u092E\u092F\u0902 \u0928\u093F\u0924\u094D\u092F\u092E\u0941\u0915\u094D\u0924\u092C\u094D\u0930\u0939\u094D\u092E\u0938\u094D\u0925\u093E\u0928\u0902 \u092A\u0930\u092E\u0902 \u092A\u0926\u092E\u094D \u0964</p><p class="trans">parama\u1E41 padamiti ca pr\u0101\u1E47endriy\u0101dyanta\u1E25kara\u1E47agu\u1E47\u0101de\u1E25 paratara\u1E41 saccid\u0101nandamaya\u1E41 nityamuktabrahmasth\u0101na\u1E41 parama\u1E41 padam \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0432\u044B\u0441\u0448\u0435\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 (\u043F\u0430\u0440\u0430\u043C\u0430\u043F\u0430\u0434\u0430). \u041E\u0431\u0438\u0442\u0435\u043B\u044C \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430, \u0432\u0435\u0447\u043D\u0430\u044F \u0441\u0432\u043E\u0431\u043E\u0434\u0430, \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u0430\u044F \u0411\u044B\u0442\u0438\u044F, \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0438 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0430\u044F \u043F\u0440\u0430\u043D\u0443, \u043E\u0440\u0433\u0430\u043D\u044B [\u0447\u0443\u0432\u0441\u0442\u0432 \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F], \u043F\u0441\u0438\u0445\u0438\u043A\u0443 (\u0430\u043D\u0442\u0430\u0445\u043A\u0430\u0440\u0430\u043D\u0430) \u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u043C\u0430\u0442\u0435\u0440\u0438\u0438 (\u0433\u0443\u043D\u0430), \u0435\u0441\u0442\u044C \u0432\u044B\u0441\u0448\u0435\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435.</p></div><div class="stanza"><a href="#s24" id="s24" class="num">24</a><p class="sans">\u0917\u094D\u0930\u093E\u0939\u094D\u092F\u092E\u093F\u0924\u093F \u091A \u0926\u0947\u0936\u0915\u093E\u0932\u0935\u0938\u094D\u0924\u0941\u092A\u0930\u093F\u091A\u094D\u091B\u0947\u0926\u0930\u093E\u0939\u093F\u0924\u094D\u092F\u091A\u093F\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u0917\u094D\u0930\u093E\u0939\u094D\u092F\u092E\u094D \u0964</p><p class="trans">gr\u0101hyamiti ca de\u015Bak\u0101lavastuparicchedar\u0101hityacinm\u0101trasvar\u016Bpa\u1E41 gr\u0101hyam \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0442\u043E\u043C, \u0447\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u044F\u0442\u044C. \u041D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u043F\u043E\u0441\u0442\u0438\u0447\u044C \u0438\u0441\u0442\u0438\u043D\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 (\u0441\u0432\u0430\u0440\u0443\u043F\u0430), \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043B\u0438\u0448\u0451\u043D\u043D\u043E\u0435 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F \u043D\u0430 \u043C\u0435\u0441\u0442\u043E, \u0432\u0440\u0435\u043C\u044F \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u044E.</p></div><div class="stanza"><a href="#s25" id="s25" class="num">25</a><p class="sans">\u0905\u0917\u094D\u0930\u093E\u0939\u094D\u092F\u092E\u093F\u0924\u093F \u091A \u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u0935\u094D\u092F\u0924\u093F\u0930\u093F\u0915\u094D\u0924\u092E\u093E\u092F\u093E\u092E\u092F\u092C\u0941\u0926\u094D\u0927\u0940\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0917\u094B\u091A\u0930\u091C\u0917\u0924\u094D\u0938\u0924\u094D\u092F\u0924\u094D\u0935\u091A\u093F\u0928\u094D\u0924\u0928\u092E\u0917\u094D\u0930\u093E\u0939\u094D\u092F\u092E\u094D \u0964</p><p class="trans">agr\u0101hyamiti ca svasvar\u016Bpavyatiriktam\u0101y\u0101mayabuddh\u012Bndriyagocarajagatsatyatvacintanamagr\u0101hyam \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0442\u043E\u043C, \u0447\u0435\u0433\u043E \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0438\u043C\u0435\u0442\u044C. \u041D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0438\u043C\u0435\u0442\u044C \u043C\u044B\u0441\u043B\u0438 \u043E \u0442\u043E\u043C, \u0447\u0442\u043E \u043C\u0438\u0440, \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0439 \u0440\u0430\u0437\u0443\u043C\u043E\u043C \u0438 \u043E\u0440\u0433\u0430\u043D\u0430\u043C\u0438 [\u0447\u0443\u0432\u0441\u0442\u0432], \u0441\u043E\u0442\u0432\u043E\u0440\u0451\u043D\u043D\u044B\u0439 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0439 \u0441\u0438\u043B\u043E\u0439 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430 (\u043C\u0430\u0439\u0435\u0439) \u0438 \u043E\u0442\u043B\u0438\u0447\u043D\u044B\u0439 \u043E\u0442 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B [\u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430], \u0435\u0441\u0442\u044C [\u043A\u043E\u043D\u0435\u0447\u043D\u0430\u044F] \u0418\u0441\u0442\u0438\u043D\u0430.</p></div><div class="stanza"><a href="#s26" id="s26" class="num">26</a><p class="sans">\u0938\u0902\u0928\u094D\u092F\u093E\u0938\u0940\u0924\u093F \u091A \u0938\u0930\u094D\u0935\u0927\u0930\u094D\u092E\u093E\u0928\u094D\u092A\u0930\u093F\u0924\u094D\u092F\u091C\u094D\u092F \u0928\u093F\u0930\u094D\u092E\u092E\u094B \u0928\u093F\u0930\u0939\u0919\u094D\u0915\u093E\u0930\u094B \u092D\u0942\u0924\u094D\u0935\u093E \u092C\u094D\u0930\u0939\u094D\u092E\u0947\u0937\u094D\u091F\u0902 \u0936\u0930\u0923\u092E\u0941\u092A\u0917\u092E\u094D\u092F \u0924\u0924\u094D\u0924\u094D\u0935\u092E\u0938\u093F \u0905\u0939\u0902 \u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0938\u094D\u092E\u093F \u0938\u0930\u094D\u0935\u0902 \u0916\u0932\u094D\u0935\u093F\u0926\u0902 \u092C\u094D\u0930\u0939\u094D\u092E \u0928\u0947\u0939 \u0928\u093E\u0928\u093E\u0938\u094D\u0924\u093F \u0915\u093F\u091E\u094D\u091A\u0928\u0947\u0924\u094D\u092F\u093E\u0926\u093F\u092E\u0939\u093E\u0935\u093E\u0915\u094D\u092F\u093E\u0930\u094D\u0925\u093E\u0928\u0941\u092D\u0935\u091C\u094D\u091E\u093E\u0928\u093E\u0926\u094D\u092C\u094D\u0930\u0939\u094D\u092E\u0948\u0935\u093E\u0939\u092E\u0938\u094D\u092E\u0940\u0924\u093F \u0928\u093F\u0936\u094D\u091A\u093F\u0924\u094D\u092F \u0928\u093F\u0930\u094D\u0935\u093F\u0915\u0932\u094D\u092A\u0938\u092E\u093E\u0927\u093F\u0928\u093E \u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u094B \u092F\u0924\u093F\u0936\u094D\u091A\u0930\u0924\u093F \u0938 \u0938\u0902\u0928\u094D\u092F\u093E\u0938\u0940 \u0938 \u092E\u0941\u0915\u094D\u0924\u0903 \u0938 \u092A\u0942\u091C\u094D\u092F\u0903 \u0938 \u092F\u094B\u0917\u0940 \u0938 \u092A\u0930\u092E\u0939\u0902\u0938\u0903 \u0938\u094B\u093D\u0935\u0927\u0942\u0924\u0903 \u0938 \u092C\u094D\u0930\u093E\u0939\u094D\u092E\u0923 \u0907\u0924\u093F \u0964</p><p class="trans">sa\u1E41ny\u0101s\u012Bti ca sarvadharm\u0101nparityajya nirmamo niraha\u1E45k\u0101ro bh\u016Btv\u0101 brahme\u1E63\u1E6Da\u1E41 \u015Bara\u1E47amupagamya tattvamasi aha\u1E41 brahm\u0101smi sarva\u1E41 khalvida\u1E41 brahma neha n\u0101n\u0101sti ki\xF1canety\u0101dimah\u0101v\u0101ky\u0101rth\u0101nubhavaj\xF1\u0101n\u0101dbrahmaiv\u0101hamasm\u012Bti ni\u015Bcitya nirvikalpasam\u0101dhin\u0101 svatantro yati\u015Bcarati sa sa\u1E41ny\u0101s\u012B sa mukta\u1E25 sa p\u016Bjya\u1E25 sa yog\u012B sa paramaha\u1E41sa\u1E25 so&#39;vadh\u016Bta\u1E25 sa br\u0101hma\u1E47a iti \u0964<br></p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E \u0442\u043E\u043C, \u043A\u0442\u043E \u0435\u0441\u0442\u044C \u0441\u0430\u043D\u043D\u044C\u044F\u0441\u0438\u043D. \u0422\u043E\u0442 \u043C\u0443\u0434\u0440\u0435\u0446, \u043A\u0442\u043E \u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u043B\u0441\u044F \u043E\u0442 \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0438 \u044D\u0433\u043E, \u043E\u0442\u0440\u0451\u043A\u0441\u044F \u043E\u0442\u043E \u0432\u0441\u0435\u0445 \u0434\u0445\u0430\u0440\u043C, \u043F\u0440\u0435\u0434\u0430\u043B\u0441\u044F \u0432\u0441\u0435\u0446\u0435\u043B\u043E \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0443, \u043E\u0441\u043E\u0437\u043D\u0430\u043B \u0441\u0435\u0431\u044F \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0443 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044E \u0441\u043C\u044B\u0441\u043B\u0430 \u0432\u0435\u043B\u0438\u043A\u0438\u0445 \u0438\u0437\u0440\u0435\u0447\u0435\u043D\u0438\u0439 \u2014 \xAB\u0422\u043E \u0442\u044B \u0435\u0441\u0442\u044C\xBB, \xAB\u042F \u0435\u0441\u0442\u044C \u0411\u0440\u0430\u0445\u043C\u0430\u043D\xBB, \xAB\u0412\u0441\u0451 \u044D\u0442\u043E \u0435\u0441\u0442\u044C \u0411\u0440\u0430\u0445\u043C\u0430\u043D, \u0431\u0435\u0437 \u043A\u0430\u043A\u0438\u0445-\u043B\u0438\u0431\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439\xBB \u0438 \u0434\u0440\u0443\u0433\u0438\u0445, \u0438 \u0436\u0438\u0432\u0451\u0442 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u043B\u0438\u0448\u0451\u043D\u043D\u043E\u043C \u0432\u0438\u043A\u0430\u043B\u044C\u043F \u044D\u043A\u0441\u0442\u0430\u0437\u0435 (\u043D\u0438\u0440\u0432\u0438\u043A\u0430\u043B\u044C\u043F\u0430-\u0441\u0430\u043C\u0430\u0434\u0445\u0438), \u0435\u0441\u0442\u044C \u0441\u0430\u043D\u043D\u044C\u044F\u0441\u0438\u043D. \u041E\u043D \u2014 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0451\u043D\u043D\u044B\u0439, \u043E\u043D \u0434\u043E\u0441\u0442\u043E\u0438\u043D \u043F\u043E\u0447\u0438\u0442\u0430\u043D\u0438\u044F, \u043E\u043D \u2014 \u0439\u043E\u0433\u0438\u043D, \u043E\u043D \u2014 \u043F\u0430\u0440\u0430\u043C\u0430\u0445\u0430\u043C\u0441\u0430, \u043E\u043D \u2014 \u0430\u0432\u0430\u0434\u0445\u0443\u0442\u0430, \u043E\u043D \u2014 \u0431\u0440\u0430\u0445\u043C\u0430\u043D.</p></div><div class="stanza"><p class="sans">\u0907\u0926\u0902 \u0928\u093F\u0930\u093E\u0932\u092E\u094D\u092C\u094B\u092A\u0928\u093F\u0937\u0926\u0902 \u092F\u094B\u093D\u0927\u0940\u0924\u0947 \u0917\u0941\u0930\u094D\u0935\u0928\u0941\u0917\u094D\u0930\u0939\u0924\u0903 \u0938\u094B\u093D\u0917\u094D\u0928\u093F\u092A\u0942\u0924\u094B \u092D\u0935\u0924\u093F \u0938 \u0935\u093E\u092F\u0941\u092A\u0942\u0924\u094B \u092D\u0935\u0924\u093F \u0928 \u0938 \u092A\u0941\u0928\u0930\u093E\u0935\u0930\u094D\u0924\u0924\u0947 \u0928 \u0938 \u092A\u0941\u0928\u0930\u093E\u0935\u0930\u094D\u0924\u0924\u0947 \u092A\u0941\u0928\u0930\u094D\u0928\u093E\u092D\u093F\u091C\u093E\u092F\u0924\u0947 \u092A\u0941\u0928\u0930\u094D\u0928\u093E\u092D\u093F\u091C\u093E\u092F\u0924 \u0907\u0924\u094D\u092F\u0941\u092A\u0928\u093F\u0937\u0924\u094D \u0965</p><p class="trans">ida\u1E41 nir\u0101lambopani\u1E63ada\u1E41 yo&#39;dh\u012Bte gurvanugrahata\u1E25 so&#39;gnip\u016Bto bhavati sa v\u0101yup\u016Bto bhavati na sa punar\u0101vartate na sa punar\u0101vartate punarn\u0101bhij\u0101yate punarn\u0101bhij\u0101yata ityupani\u1E63at \u0965</p><p>\u0422\u043E\u0442, \u043A\u0442\u043E \u0438\u0437\u0443\u0447\u0430\u0435\u0442 \u044D\u0442\u0443 \xAB\u041D\u0438\u0440\u0430\u043B\u0430\u043C\u0431\u0430 \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0443\xBB, \u043F\u043E \u043C\u0438\u043B\u043E\u0441\u0442\u0438 \u0413\u0443\u0440\u0443 (\u0428\u0438\u0432\u044B) \u043E\u0447\u0438\u0449\u0430\u0435\u0442\u0441\u044F \u043E\u0433\u043D\u0451\u043C [\u043B\u044E\u0431\u0432\u0438] \u0438 \u043E\u0447\u0438\u0449\u0430\u0435\u0442\u0441\u044F \u0432\u043E\u0437\u0434\u0443\u0445\u043E\u043C [\u0437\u043D\u0430\u043D\u0438\u044F]. \u0412\u043E\u0438\u0441\u0442\u0438\u043D\u0443, \u043E\u043D \u0431\u043E\u043B\u0435\u0435 \u043D\u0435 \u0441\u0432\u044F\u0437\u0430\u043D \u043F\u0435\u0440\u0435\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F\u043C\u0438\xBB.</p></div><div class="stanza"><p class="sans">\u0950 \u092A\u0942\u0930\u094D\u0923\u092E\u0926\u0903 \u092A\u0942\u0930\u094D\u0923\u092E\u093F\u0926\u0902 \u092A\u0942\u0930\u094D\u0923\u093E\u0924\u094D\u092A\u0942\u0930\u094D\u0923\u092E\u0941\u0926\u091A\u094D\u092F\u0924\u0947 \u0964<br> \u092A\u0942\u0930\u094D\u0923\u0938\u094D\u092F \u092A\u0942\u0930\u094D\u0923\u092E\u093E\u0926\u093E\u092F \u092A\u0942\u0930\u094D\u0923\u092E\u0947\u0935\u093E\u0935\u0936\u093F\u0937\u094D\u092F\u0924\u0947 \u0965<br> \u0950 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0965</p><p class="trans">o\u1E41 p\u016Br\u1E47amada\u1E25 p\u016Br\u1E47amida\u1E41 p\u016Br\u1E47\u0101tp\u016Br\u1E47amudacyate \u0964<br> p\u016Br\u1E47asya p\u016Br\u1E47am\u0101d\u0101ya p\u016Br\u1E47amev\u0101va\u015Bi\u1E63yate \u0965<br> o\u1E41 \u015B\u0101nti\u1E25 \u015B\u0101nti\u1E25 \u015B\u0101nti\u1E25 \u0965</p><p>\u041E\u043C. \u0422\u043E \u2014 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C, \u0438 \u044D\u0442\u043E \u2014 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C. \u0411\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C \u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0438\u0437 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u0438, \u041E\u0431\u0440\u0435\u0442\u0430\u044F \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0433\u043E, \u043E\u043D\u0430 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u043B\u0438\u0448\u044C \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C\u044E. \u041E\u043C! \u041F\u043E\u043A\u043E\u0439! \u041F\u043E\u043A\u043E\u0439! \u041F\u043E\u043A\u043E\u0439! \xA0</p></div><p class="sans">\u0965 \u0907\u0924\u093F \u0928\u093F\u0930\u093E\u0932\u092E\u094D\u092C\u094B\u092A\u0928\u093F\u0937\u0924\u094D\u0938\u092E\u093E\u092A\u094D\u0924\u093E \u0965</p><p class="trans">.. iti nir\u0101lambopani\u1E63atsam\u0101pt\u0101 \u0965</p><p>\u0422\u0430\u043A\u043E\u0432\u0430 \xAB\u041D\u0438\u0440\u0430\u043B\u0430\u043C\u0431\u0430 \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430\xBB \u0428\u0443\u043A\u043B\u0430-\u042F\u0434\u0436\u0443\u0440\u0432\u0435\u0434\u044B.</p><p><a href="/books/niralamba.pdf" target="_blank">\u0421\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0439 \u0442\u0435\u043A\u0441\u0442 \u041D\u0438\u0440\u0430\u043B\u0430\u043C\u0431\u0430 \u0423\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u044B</a></p>',40),p=[t];function d(b,m,v,c,h,l){return r(),s("div",null,p)}var e=a(n,[["render",d]]);export{k as __pageData,e as default};
